import { useContext } from 'react';
import { AppPageRouteContext } from "./internal/app-page-route-context.js";
/**
 * The hook that provides the current page route to the component.
 *
 * @returns The current page route.
 */
export const usePageRoute = () => {
    const matchedPageRoute = useContext(AppPageRouteContext);
    if (!matchedPageRoute) {
        throw new Error('usePageRoute must be used within a <PageRouter> component produced by createPageRouter. \nSee: https://developers.hubspot.com/docs/apps/developer-platform/add-features/ui-extensions/extension-points/app-pages/page-routing#getting-the-current-page-path');
    }
    return matchedPageRoute;
};
